[{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"EditURL = \"../../../lit/mri/3-2d-t.jl\"","category":"page"},{"location":"generated/mri/3-2d-t/#3-2d-t","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"","category":"section"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"This example illustrates 2D dynamic MRI image reconstruction from golden angle (GA) radial sampled k-space data collected with multiple coils (parallel MRI), with temporal \"TV\" regularizer (corner-rounded) using the Julia language.","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"This page comes from a single Julia file: 3-2d-t.jl.","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"You can access the source code for such Julia documentation using the 'Edit on GitHub' link in the top right. You can view the corresponding notebook in nbviewer here: 3-2d-t.ipynb, or open it in binder here: 3-2d-t.ipynb.","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"using ImageGeoms: ImageGeom\nusing ImagePhantoms: shepp_logan, SouthPark, phantom, ellipse, spectrum\nusing MIRTjim: jim, prompt\nusing MIRT: Anufft, diffl_map, ncg\nusing MIRT: ir_mri_sensemap_sim, ir_mri_kspace_ga_radial\nusing Plots: gui, plot, scatter, default; default(markerstrokecolor=:auto, label=\"\")\nusing Plots: gif, @animate, Plots\nusing LinearAlgebra: norm, dot, Diagonal\nusing LinearMapsAA: LinearMapAA, block_diag\nusing Random: seed!\njim(:abswarn, false); # suppress warnings about display of |complex| images\nnothing #hide","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"The following line is helpful when running this jl-file as a script; this way it will prompt user to hit a key after each image is displayed.","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"isinteractive() && jim(:prompt, true);\nnothing #hide","category":"page"},{"location":"generated/mri/3-2d-t/#Define-dynamic-image-sequence","page":"2D dynamic: temporal TV","title":"Define dynamic image sequence","text":"","category":"section"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"N = (60,64)\nfov = 220\nnt = 8 # frames\nig = ImageGeom(; dims = N, deltas=(fov,fov) ./ N)\n\nobject0 = shepp_logan(SouthPark(); fovs = (fov,fov))\nobjects = Array{typeof(object0)}(undef, nt)\nxtrue = Array{ComplexF32}(undef, N..., nt)\nfor it in 1:nt\n    tmp = copy(object0)\n    width2 = 15 + 5 * sin(2π*it/nt) # mouth open/close\n    mouth = tmp[2]\n    tmp[2] = ellipse(mouth.center, (mouth.width[1], width2), mouth.angle[1], mouth.value)\n    objects[it] = tmp\n    xtrue[:,:,it] = phantom(axes(ig)..., tmp, 4)\nend\njimxy = (args...; aspect_ratio=1, kwargs...) ->\n    jim(axes(ig)..., args...; aspect_ratio, kwargs...)\njimxy(xtrue, \"True images\"; nrow=2)","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"Animate true image:","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"anim1 = @animate for it in 1:nt\n    jimxy(xtrue[:,:,it], title=\"Frame $it\")\nend\ngif(anim1; fps = 6)","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"Plot one time course to see temporal change:","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"ix,iy = 30,14\nplot(1:nt, abs.(xtrue[ix,iy,:]), label=\"ix=$ix, iy=$iy\",\n    marker=:o, xlabel=\"frame\")","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"isinteractive() && prompt();\nnothing #hide","category":"page"},{"location":"generated/mri/3-2d-t/#Define-k-space-sampling","page":"2D dynamic: temporal TV","title":"Define k-space sampling","text":"","category":"section"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"accelerate = 3\nnspf = round(Int, maximum(N)/accelerate) # spokes per frame\n\nNro = maximum(N)\nNspoke = nspf * nt\nkspace = ir_mri_kspace_ga_radial(; Nro, Nspoke)\nfovs = (fov, fov)\nkspace[:,:,1] ./= fovs[1]\nkspace[:,:,2] ./= fovs[2]\nkspace = reshape(kspace, Nro, nspf, nt, 2)\n(size(kspace), extrema(kspace))","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"Plot sampling (in units of cycles/pixel):","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"ps = Array{Any}(undef, nt)\nfor it in 1:nt\n    ps[it] = scatter(kspace[:,:,it,1] * fovs[1], kspace[:,:,it,2] * fovs[2],\n        xtick=(-1:1)*0.5, ytick=(-1:1)*0.5, xlim=(-1,1).*0.5, ylim=(-1,1).*0.5,\n        aspect_ratio=1, markersize=1, title=\"Frame $it\", widen=true)\nend\nplot(ps...; layout=(2,4))","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"isinteractive() && prompt();\n\nanim2 = @animate for it in 1:nt\n    plot(ps[it])\nend\ngif(anim2; fps = 6)","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"Make sensitivity maps, normalized so SSoS = 1:","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"ncoil = 2\nsmap_raw = ir_mri_sensemap_sim(dims=N, ncoil=ncoil, orbit_start=[90])\np1 = jim(smap_raw, \"Sensitivity maps raw\");\n\nsum_last = (f, x) -> selectdim(sum(f, x; dims=ndims(x)), ndims(x), 1)\nssos_fun = smap -> sqrt.(sum_last(abs2, smap)) # SSoS\nssos_raw = ssos_fun(smap_raw)\np2 = jim(ssos_raw, \"SSoS for ncoil=$ncoil\");\n\nsmap = smap_raw ./ ssos_raw\np3 = jim(smap, \"Sensitivity maps\");\n\nssos = ssos_fun(smap) # SSoS\n@assert all(≈(1), ssos)\njim(p1, p2, p3)","category":"page"},{"location":"generated/mri/3-2d-t/#System-matrix","page":"2D dynamic: temporal TV","title":"System matrix","text":"","category":"section"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"Make system matrix for dynamic non-Cartesian parallel MRI:","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"Fs = Array{Any}(undef, nt)\nfor it in 1:nt # a NUFFT object for each frame\n    Ω = [kspace[:,:,it,1][:] kspace[:,:,it,2][:]] * fov * 2pi\n    Fs[it] = Anufft(Ω, N, n_shift = [N...]/2)\nend","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"Block diagonal system matrix, with one NUFFT per frame","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"S = [Diagonal(vec(selectdim(smap, ndims(smap), ic))) for ic in 1:ncoil]\nSO = s -> LinearMapAA(s ; idim=N, odim=N) # LinearMapAO for coil maps\nAS1 = F -> vcat([F * SO(s) for s in S]...); # [A1*S1; ... ; A1*Sncoil]\nnothing #hide","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"Linear operator input is (N..., nt), output is (nspf*Nro, Ncoil, nt)","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"A = block_diag([AS1(F) for F in Fs]...) # todo: refine show()\n(size(A), A._odim, A._idim)","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"Simulate k-space data via an inverse crime (todo):","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"ytrue = A * xtrue\nsnr2sigma = (db, yb) -> # compute noise sigma from SNR (no sqrt(2) needed)\n    10^(-db/20) * norm(yb) / sqrt(length(yb))\nsig = Float32(snr2sigma(50, ytrue))\nseed!(0)\ny = ytrue + sig * randn(ComplexF32, size(ytrue))\nysnr = 20*log10(norm(ytrue) / norm(y - ytrue)) # verify SNR","category":"page"},{"location":"generated/mri/3-2d-t/#Initial-image","page":"2D dynamic: temporal TV","title":"Initial image","text":"","category":"section"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"Initial image via zero-fill and scaling: todo: should use density compensation, perhaps via VoronoiDelaunay.jl","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"x0 = A' * y # zero-filled recon (for each frame)\ntmp = A * x0 # (Nkspace, Ncoil, Nframe)\nx0 = (dot(tmp,y) / norm(tmp)^2) * x0 # scale sensibly\njimxy(x0, \"initial image\"; nrow=2)","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"Temporal finite differences:","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"Dt = diffl_map((N..., nt), length(N)+1 ; T=eltype(A))\ntmp = Dt' * (Dt * xtrue)\njimxy(tmp, \"Time differences are sparse\"; nrow=2)","category":"page"},{"location":"generated/mri/3-2d-t/#Regularized-CG-reconstruction","page":"2D dynamic: temporal TV","title":"Regularized CG reconstruction","text":"","category":"section"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"Run nonlinear CG on \"temporal edge-preserving\" regularized LS cost function","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"niter = 90\ndelta = Float32(0.1) # small relative to temporal differences\nreg = Float32(2^20) # trial and error here\nffair = (t,d) -> d^2 * (abs(t)/d - log(1 + abs(t)/d))\npot = z -> ffair(z, delta)\ndpot = z -> z / (Float32(1) + abs(z/delta))\ncost = x -> 0.5 * norm(A*x - y)^2 + reg * sum(pot.(Dt * x))\nfun = (x,iter) -> cost(x)\ngradf = [v -> v - y, u -> reg * dpot.(u)]\ncurvf = [v -> Float32(1), u -> reg]\n(xh, out) = ncg([A, Dt], gradf, curvf, x0 ; niter, fun)\ncosts = [out[i+1][1] for i=0:niter];\nnothing #hide","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"Show results","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"pr = plot(\n    jimxy(xtrue, \"|xtrue|\"; nrow=2),\n    jimxy(xh, \"|recon|\"; nrow=2),\n    jimxy(xh-xtrue, \"|error|\"; nrow=2),\n    scatter(0:niter, log.(costs), label=\"cost\", xlabel=\"iteration\"),\n)","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"isinteractive() && prompt();\nnothing #hide","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"Animate true, recon, error","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"anim3 = @animate for it in 1:nt\n    plot(\n        jimxy(xtrue[:,:,it], clim=(0,120), title=\"True\"),\n        jimxy(xh[:,:,it], clim=(0,120), title=\"|Recon|\"),\n        jimxy(xh[:,:,it] - xtrue[:,:,it], clim=(0,30), title=\"|Error|\"),\n        plot_title = \"Frame $it\",\n        layout = (1,3),\n    )\nend\ngif(anim3; fps = 6)","category":"page"},{"location":"generated/mri/3-2d-t/#Reproducibility","page":"2D dynamic: temporal TV","title":"Reproducibility","text":"","category":"section"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"This page was generated with the following version of Julia:","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"using InteractiveUtils: versioninfo\nio = IOBuffer(); versioninfo(io); split(String(take!(io)), '\\n')","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"And with the following package versions","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"import Pkg; Pkg.status()","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"","category":"page"},{"location":"generated/mri/3-2d-t/","page":"2D dynamic: temporal TV","title":"2D dynamic: temporal TV","text":"This page was generated using Literate.jl.","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"EditURL = \"../../../lit/mri/2-cs-wl-l1-2d.jl\"","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/#2-cs-wl-l1-2d","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"","category":"section"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"This example illustrates how to perform 2D compressed sensing image reconstruction from Cartesian sampled MRI data with 1-norm regularization of orthogonal wavelet coefficients, using the Julia language.","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"This page comes from a single Julia file: 2-cs-wl-l1-2d.jl.","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"You can access the source code for such Julia documentation using the 'Edit on GitHub' link in the top right. You can view the corresponding notebook in nbviewer here: 2-cs-wl-l1-2d.ipynb, or open it in binder here: 2-cs-wl-l1-2d.ipynb.","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"This demo is somewhat similar to Fig. 3 in the survey paper \"Optimization methods for MR image reconstruction,\" in Jan 2020 IEEE Signal Processing Magazine, except that the sampling is 1D phase encoding instead of 2D.","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"Packages used in this demo (run Pkg.add as needed):","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"using ImagePhantoms: shepp_logan, SheppLoganEmis, spectrum, phantom\nusing MIRT: embed, Afft, Aodwt\nusing MIRTjim: jim, prompt\nusing MIRT: pogm_restart\nusing LinearAlgebra: norm\nusing Plots; default(markerstrokecolor=:auto, label=\"\")\nusing FFTW: fft\nusing Random: seed!\nusing InteractiveUtils: versioninfo","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"The following line is helpful when running this jl-file as a script; this way it will prompt user to hit a key after each image is displayed.","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"isinteractive() && jim(:prompt, true);\nnothing #hide","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/#Create-(synthetic)-data","page":"Compressed Sensing 2D","title":"Create (synthetic) data","text":"","category":"section"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"Shepp-Logan phantom (unrealistic because real-valued):","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"nx,ny = 192,256\nobject = shepp_logan(SheppLoganEmis(); fovs=(ny,ny))\nXtrue = phantom(-(nx÷2):(nx÷2-1), -(ny÷2):(ny÷2-1), object, 2)\nXtrue = reverse(Xtrue, dims=2)\nclim = (0,9)\njim(Xtrue, \"true image\"; clim)","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"Somewhat random 1D phase-encode sampling:","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"seed!(0); sampfrac = 0.2; samp = rand(ny) .< sampfrac; sig = 1\nmod2 = (N) -> mod.((0:N-1) .+ Int(N/2), N) .- Int(N/2)\nsamp .|= (abs.(mod2(ny)) .< Int(ny/8)) # fully sampled center rows\nsamp = trues(nx) * samp'\njim(samp, fft0=true, title=\"k-space sampling ($(100count(samp)/(nx*ny))%)\")","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"Generate noisy, under-sampled k-space data (inverse-crime simulation):","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"ytrue = fft(Xtrue)[samp]\ny = ytrue + sig * √(2) * randn(ComplexF32, size(ytrue)) # complex noise!\ny = ComplexF32.(y) # save memory\nysnr = 20 * log10(norm(ytrue) / norm(y-ytrue)) # data SNR in dB","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"Display zero-filled data:","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"logger = (x; min=-6) -> log10.(max.(abs.(x) / maximum(abs, x), (10.)^min))\njim(:abswarn, false) # suppress warnings about showing magnitude\njim(logger(embed(ytrue,samp)), fft0=true, title=\"k-space |data| (zero-filled)\",\n    xlabel=\"kx\", ylabel=\"ky\")","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/#Prepare-to-reconstruct","page":"Compressed Sensing 2D","title":"Prepare to reconstruct","text":"","category":"section"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"Creating a system matrix (encoding matrix) and an initial image The system matrix is a LinearMapAA object, akin to a fatrix in Matlab MIRT.","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"System model (\"encoding matrix\") from MIRT:","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"F = Afft(samp) # operator!","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"Initial image based on zero-filled reconstruction:","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"nrmse = (x) -> round(norm(x - Xtrue) / norm(Xtrue) * 100, digits=1)\nX0 = 1.0f0/(nx*ny) * (F' * y)\njim(X0, \"|X0|: initial image; NRMSE $(nrmse(X0))%\")","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/#Wavelet-sparsity-in-synthesis-form","page":"Compressed Sensing 2D","title":"Wavelet sparsity in synthesis form","text":"","category":"section"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"The image reconstruction optimization problem here is","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"arg min_x\nfrac12  A x - y _2^2 + beta   W x _1","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"where y is the k-space data, A is the system model (simply Fourier encoding F here), W is an orthogonal discrete (Haar) wavelet transform, again implemented as a LinearMapAA object. Because W is unitary, we make the change of variables z = W x and solve for z and then let x = W z at the end. In fact we use a weighted 1-norm where only the detail wavelet coefficients are regularized, not the approximation coefficients.","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"Orthogonal discrete wavelet transform operator (LinearMapAO):","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"W, scales, _ = Aodwt((nx,ny) ; T = eltype(F))\nisdetail = scales .> 0\njim(\n    jim(scales, \"wavelet scales\"),\n    jim(real(W * Xtrue) .* isdetail, \"wavelet detail coefficients\"),\n)","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"Inputs needed for proximal gradient methods:","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"Az = F * W' # another operator!\nFnullz = (z) -> 0 # cost function in `z` not needed\nf_gradz = (z) -> Az' * (Az * z - y)\nf_Lz = nx*ny # Lipschitz constant for single coil Cartesian DFT\nregz = 0.03 * nx * ny # oracle from Xtrue wavelet coefficients!\ncostz = (z) -> 1/2 * norm(Az * z - y)^2 + regz * norm(z,1) # 1-norm regularizer\nsoft = (z,c) -> sign(z) * max(abs(z) - c, 0) # soft thresholding\ng_prox = (z,c) -> soft.(z, isdetail .* (regz * c)) # proximal operator (shrink details only)\nz0 = W * X0\njim(z0, \"Initial wavelet coefficients\")","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/#Iterate","page":"Compressed Sensing 2D","title":"Iterate","text":"","category":"section"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"Run ISTA=PGM and FISTA=FPGM and POGM, the latter two with adaptive restart See Kim & Fessler, 2018 for adaptive restart algorithm details.","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"Functions for tracking progress:","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"function fun_ista(iter, xk_z, yk, is_restart)\n    xh = W' * xk_z\n    return (costz(xk_z), nrmse(xh), is_restart) # , psnr(xh)) # time()\nend\n\nfunction fun_fista(iter, xk, yk_z, is_restart)\n    xh = W' * yk_z\n    return (costz(yk_z), nrmse(xh), is_restart) # , psnr(xh)) # time()\nend;\nnothing #hide","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"Run and compare three proximal gradient methods:","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"niter = 50\nz_ista, out_ista = pogm_restart(z0, Fnullz, f_gradz, f_Lz; mom=:pgm, niter=niter,\n    restart=:none, restart_cutoff=0., g_prox=g_prox, fun=fun_ista)\nXista = W'*z_ista\n@show nrmse(Xista)\n\nz_fista, out_fista = pogm_restart(z0, Fnullz, f_gradz, f_Lz; mom=:fpgm, niter=niter,\n    restart=:gr, restart_cutoff=0., g_prox=g_prox, fun=fun_fista)\nXfista = W'*z_fista\n@show nrmse(Xfista)\n\nz_pogm, out_pogm = pogm_restart(z0, Fnullz, f_gradz, f_Lz; mom=:pogm, niter=niter,\n    restart=:gr, restart_cutoff=0., g_prox=g_prox, fun=fun_fista)\nXpogm = W'*z_pogm\n@show nrmse(Xpogm)\n\njim(\n    jim(Xfista, \"FISTA/FPGM\"),\n    jim(Xpogm, \"POGM with ODWT\"),\n)","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/#POGM-is-fastest","page":"Compressed Sensing 2D","title":"POGM is fastest","text":"","category":"section"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"Plot cost function vs iteration:","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"cost_ista = [out_ista[k][1] for k=1:niter+1]\ncost_fista = [out_fista[k][1] for k=1:niter+1]\ncost_pogm = [out_pogm[k][1] for k=1:niter+1]\ncost_min = min(minimum(cost_ista), minimum(cost_pogm))\nplot(xlabel=\"iteration k\", ylabel=\"Relative cost\")\nscatter!(0:niter, cost_ista  .- cost_min, label=\"Cost ISTA\")\nscatter!(0:niter, cost_fista .- cost_min, markershape=:square, label=\"Cost FISTA\")\nscatter!(0:niter, cost_pogm  .- cost_min, markershape=:utriangle, label=\"Cost POGM\")","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"isinteractive() && prompt();\nnothing #hide","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"Plot NRMSE vs iteration:","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"nrmse_ista = [out_ista[k][2] for k=1:niter+1]\nnrmse_fista = [out_fista[k][2] for k=1:niter+1]\nnrmse_pogm = [out_pogm[k][2] for k=1:niter+1]\npn = plot(xlabel=\"iteration k\", ylabel=\"NRMSE %\", ylims=(3,6.5))\nscatter!(0:niter, nrmse_ista, label=\"NRMSE ISTA\")\nscatter!(0:niter, nrmse_fista, markershape=:square, label=\"NRMSE FISTA\")\nscatter!(0:niter, nrmse_pogm, markershape=:utriangle, label=\"NRMSE POGM\")","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"Show error images:","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"p1 = jim(Xtrue, \"true\")\np2 = jim(X0, \"X0: initial\")\np3 = jim(Xpogm, \"POGM recon\")\np5 = jim(X0 - Xtrue, \"X0 error\", clim=(0,2))\np6 = jim(Xpogm - Xtrue, \"Xpogm error\", clim=(0,2))\npe = jim(p2, p3, p5, p6)","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/#Reproducibility","page":"Compressed Sensing 2D","title":"Reproducibility","text":"","category":"section"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"This page was generated with the following version of Julia:","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"using InteractiveUtils: versioninfo\nio = IOBuffer(); versioninfo(io); split(String(take!(io)), '\\n')","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"And with the following package versions","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"import Pkg; Pkg.status()","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"","category":"page"},{"location":"generated/mri/2-cs-wl-l1-2d/","page":"Compressed Sensing 2D","title":"Compressed Sensing 2D","text":"This page was generated using Literate.jl.","category":"page"},{"location":"generated/ct/1-fbp/","page":"FBP Overview","title":"FBP Overview","text":"EditURL = \"../../../lit/ct/1-fbp.jl\"","category":"page"},{"location":"generated/ct/1-fbp/#1-fbp","page":"FBP Overview","title":"FBP Overview","text":"","category":"section"},{"location":"generated/ct/1-fbp/","page":"FBP Overview","title":"FBP Overview","text":"This example illustrates how to perform filtered back-projection (FBP) image reconstruction in CT using the Julia language.","category":"page"},{"location":"generated/ct/1-fbp/","page":"FBP Overview","title":"FBP Overview","text":"This is under construction. See the demos in the Sinograms.jl package instead.","category":"page"},{"location":"generated/ct/1-fbp/","page":"FBP Overview","title":"FBP Overview","text":"This page comes from a single Julia file: 1-fbp.jl.","category":"page"},{"location":"generated/ct/1-fbp/","page":"FBP Overview","title":"FBP Overview","text":"You can access the source code for such Julia documentation using the 'Edit on GitHub' link in the top right. You can view the corresponding notebook in nbviewer here: 1-fbp.ipynb, or open it in binder here: 1-fbp.ipynb.","category":"page"},{"location":"generated/ct/1-fbp/","page":"FBP Overview","title":"FBP Overview","text":"First we add the Julia packages that are need for these examples. Change false to true in the following code block if you are using any of the following packages for the first time.","category":"page"},{"location":"generated/ct/1-fbp/","page":"FBP Overview","title":"FBP Overview","text":"if false\n    import Pkg\n    Pkg.add([\n        \"ImagePhantoms\"\n        \"Unitful\"\n        \"Plots\"\n        \"LaTeXStrings\"\n        \"MIRTjim\"\n        \"MIRT\"\n        \"Sinograms\"\n        \"InteractiveUtils\"\n    ])\nend","category":"page"},{"location":"generated/ct/1-fbp/","page":"FBP Overview","title":"FBP Overview","text":"Now tell this Julia session to use the following packages for this example. Run Pkg.add() in the preceding code block first, if needed.","category":"page"},{"location":"generated/ct/1-fbp/","page":"FBP Overview","title":"FBP Overview","text":"using ImagePhantoms: shepplogan, SheppLogan, radon, phantom using Unitful: mm using Plots; default(label=\"\", markerstrokecolor=:auto) using LaTeXStrings using MIRT: difflmap, ncg using Sinograms: todo","category":"page"},{"location":"generated/ct/1-fbp/","page":"FBP Overview","title":"FBP Overview","text":"using MIRTjim: jim, prompt\nusing InteractiveUtils: versioninfo","category":"page"},{"location":"generated/ct/1-fbp/","page":"FBP Overview","title":"FBP Overview","text":"The following line is helpful when running this jl-file as a script; this way it will prompt user to hit a key after each image is displayed.","category":"page"},{"location":"generated/ct/1-fbp/","page":"FBP Overview","title":"FBP Overview","text":"isinteractive() && jim(:prompt, true);\nnothing #hide","category":"page"},{"location":"generated/ct/1-fbp/","page":"FBP Overview","title":"FBP Overview","text":"isinteractive() && prompt();\nnothing #hide","category":"page"},{"location":"generated/ct/1-fbp/","page":"FBP Overview","title":"FBP Overview","text":"Get the ellipse parameters for a CT-suitable version of the Shepp-Logan phantom and calculate (analytically) its sinogram.","category":"page"},{"location":"generated/ct/1-fbp/","page":"FBP Overview","title":"FBP Overview","text":"if false object = shepplogan(SheppLogan(); fovs=(FOV,FOV)) sino = radon(object).(r,ϕ') data = data / oneunit(eltype(data)) # abandon units at this point jim(kr, kϕ, abs.(data), title=\"k-space data magnitude\",     xlabel=L\"kr\",     ylabel=L\"k{\\phi}\",     xticks = (-1:1) .* maximum(abs, kr),     yticks = (0,π),     ylims = (0,π),     aspectratio = :none, ) end","category":"page"},{"location":"generated/ct/1-fbp/#Reproducibility","page":"FBP Overview","title":"Reproducibility","text":"","category":"section"},{"location":"generated/ct/1-fbp/","page":"FBP Overview","title":"FBP Overview","text":"This page was generated with the following version of Julia:","category":"page"},{"location":"generated/ct/1-fbp/","page":"FBP Overview","title":"FBP Overview","text":"using InteractiveUtils: versioninfo\nio = IOBuffer(); versioninfo(io); split(String(take!(io)), '\\n')","category":"page"},{"location":"generated/ct/1-fbp/","page":"FBP Overview","title":"FBP Overview","text":"And with the following package versions","category":"page"},{"location":"generated/ct/1-fbp/","page":"FBP Overview","title":"FBP Overview","text":"import Pkg; Pkg.status()","category":"page"},{"location":"generated/ct/1-fbp/","page":"FBP Overview","title":"FBP Overview","text":"","category":"page"},{"location":"generated/ct/1-fbp/","page":"FBP Overview","title":"FBP Overview","text":"This page was generated using Literate.jl.","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"EditURL = \"../../../lit/mri/1-nufft.jl\"","category":"page"},{"location":"generated/mri/1-nufft/#1-nufft","page":"NUFFT Overview","title":"NUFFT Overview","text":"","category":"section"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"This example illustrates how to use Nonuniform FFT (NUFFT) for image reconstruction in MRI using the Julia language.","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"This page comes from a single Julia file: 1-nufft.jl.","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"You can access the source code for such Julia documentation using the 'Edit on GitHub' link in the top right. You can view the corresponding notebook in nbviewer here: 1-nufft.ipynb, or open it in binder here: 1-nufft.ipynb.","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"Some MRI scans use non-Cartesian sampling patterns (like radial and spiral k-space trajectories, among others), often in the interest of acquisition speed.","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"Image reconstruction from fully sampled Cartesian k-space data typically uses simple inverse FFT operations, whereas non-Cartesian sampling requires more complicated methods.","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"The examples here illustrate both non-iterative (aka \"gridding\") and iterative methods for non-Cartesian MRI reconstruction. For simplicity the examples consider the case of single-coil data and ignore the effects of B0 field inhomogeneity.","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"First we add the Julia packages that are need for these examples. Change false to true in the following code block if you are using any of the following packages for the first time.","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"if false\n    import Pkg\n    Pkg.add([\n        \"ImagePhantoms\"\n        \"Unitful\"\n        \"Plots\"\n        \"LaTeXStrings\"\n        \"MIRTjim\"\n        \"MIRT\"\n        \"InteractiveUtils\"\n    ])\nend","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"Now tell this Julia session to use the following packages. Run Pkg.add() in the preceding code block first, if needed.","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"using ImagePhantoms: shepp_logan, SheppLoganEmis, spectrum, phantom #, Gauss2\nusing Unitful: mm # Allows use of physical units (mm here)\nusing Plots; default(label=\"\", markerstrokecolor=:auto)\nusing LaTeXStrings # for LaTeX in plot labels, e.g., L\"\\alpha_n\"\nusing MIRTjim: jim, prompt # jiffy image display\nusing MIRT: Anufft, diffl_map, ncg\nusing InteractiveUtils: versioninfo","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"The following line is helpful when running this file as a script; this way it will prompt user to hit a key after each image is displayed.","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"isinteractive() && jim(:prompt, true);\nnothing #hide","category":"page"},{"location":"generated/mri/1-nufft/#Radial-k-space-sampling","page":"NUFFT Overview","title":"Radial k-space sampling","text":"","category":"section"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"We focus on radial sampling as a simple representative non-Cartesian case. Consider imaging a 256mm × 256mm field of FOV with the goal of reconstructing a 128 × 128 pixel image. The following radial and angular k-space sampling is reasonable.","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"N = 128\nFOV = 256mm # physical units!\nΔx = FOV / N # pixel size\nkmax = 1 / 2Δx\nkr = ((-N÷2):(N÷2)) / (N÷2) * kmax # radial sampling in k-space\nNϕ = 3N÷2 # theoretically should be about π/2 * N\nkϕ = (0:Nϕ-1)/Nϕ * π # angular samples\nνx = kr * cos.(kϕ)' # N × Nϕ k-space sampling in cycles/mm\nνy = kr * sin.(kϕ)'\nplot(νx, νy,\n    xlabel=L\"\\nu_x\", ylabel=L\"\\nu_y\",\n    aspect_ratio = 1,\n    title = \"Radial k-space sampling\",\n)","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"isinteractive() && prompt();\nnothing #hide","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"For the NUFFT routines considered here, the sampling arguments must be \"Ω\" values: digital frequencies have pseudo-units of radians / pixel.","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"Ωx = (2π * Δx) * νx # N × Nϕ grid of k-space sample locations\nΩy = (2π * Δx) * νy # in pseudo-units of radians / sample\n\nscatter(Ωx, Ωy,\n    xlabel=L\"\\Omega_x\", ylabel=L\"\\Omega_y\",\n    xticks=((-1:1)*π, [\"-π\", \"0\", \"π\"]),\n    yticks=((-1:1)*π, [\"-π\", \"0\", \"π\"]),\n    xlims=(-π,π) .* 1.1,\n    ylims=(-π,π) .* 1.1,\n    aspect_ratio = 1, markersize = 0.5,\n    title = \"Radial k-space sampling\",\n)","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"isinteractive() && prompt();\nnothing #hide","category":"page"},{"location":"generated/mri/1-nufft/#Radial-k-space-data-for-Shepp-Logan-phantom","page":"NUFFT Overview","title":"Radial k-space data for Shepp-Logan phantom","text":"","category":"section"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"Get the ellipse parameters for a MRI-suitable version of the Shepp-Logan phantom and calculate (analytically) the radial k-space data. Then display in polar coordinates.","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"object = shepp_logan(SheppLoganEmis(); fovs=(FOV,FOV))\n#object = [Gauss2(18mm, 0mm, 100mm, 70mm, 0, 1)] # useful for validating DCF\ndata = spectrum(object).(νx,νy)\ndata = data / oneunit(eltype(data)) # abandon units at this point\njim(kr, kϕ, abs.(data), title=\"k-space data magnitude\",\n    xlabel=L\"k_r\",\n    ylabel=L\"k_{\\phi}\",\n    xticks = (-1:1) .* maximum(abs, kr),\n    yticks = (0,π),\n    ylims = (0,π),\n    aspect_ratio = :none,\n)","category":"page"},{"location":"generated/mri/1-nufft/#Non-iterative-gridding-image-reconstruction","page":"NUFFT Overview","title":"Non-iterative gridding image reconstruction","text":"","category":"section"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"It would be impossible for a radiologist to diagnose a patient from the k-space data in polar coordinates, so image reconstruction is needed.","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"The simplest approach is to (nearest-neighbor) interpolate the k-space data onto a Cartesian grid, and then reconstruction with an inverse FFT.","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"One way to do that interpolation is to use a Histogram method in Julia's statistics package.","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"using StatsBase: fit, Histogram, weights","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"The following function is a work-around because weights in StatsBase is limited to Real data, so here we bin the real and imaginary k-space data separately, and handle the units.","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"function histogram(coord, vals::AbstractArray{<:Number}, edges)\n    u = oneunit(eltype(vals))\n    wr = weights(real(vec(vals / u)))\n    wi = weights(imag(vec(vals / u)))\n    tmp1 = fit(Histogram, coord, wr, edges)\n    tmp2 = fit(Histogram, coord, wi, edges)\n    return u * complex.(tmp1.weights, tmp2.weights)\nend\n\nkx = N * Δx * νx # N × Nϕ k-space sampling in cycles/mm\nky = N * Δx * νy\nbin = (-(N÷2):(N÷2)) .- 0.5 # (N+1,) histogram bin edges\ngridded1 = histogram((vec(kx), vec(ky)), data, (bin,bin))\n\nusing FFTW: ifft, fftshift\ntmp = fftshift(ifft(fftshift(gridded1)))\nx = (-(N÷2):(N÷2-1)) * Δx\ny = (-(N÷2):(N÷2-1)) * Δx\njim(x, y, tmp, title=\"Elementary gridding reconstruction\")","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"That crummy gridding method does not work well. Here's what the phantom should look like:","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"ideal = phantom(x, y, object, 2)\nclim = (0, 9)\np0 = jim(x, y, ideal, title=\"True Shepp-Logan phantom\"; clim)","category":"page"},{"location":"generated/mri/1-nufft/#NUFFT-approach-to-gridding","page":"NUFFT Overview","title":"NUFFT approach to gridding","text":"","category":"section"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"Basic nearest-neighbor gridding does not provide acceptable image quality in MRI, so now we turn to using the NUFFT. For MRI purposes, the NUFFT is a function that maps Cartesian spaced image data into non-Cartesian k-space data. The NFFT.jl package has functions for computing the NUFFT and its adjoint. These are linear mappings (generalizations of matrices), so instead of calling those functions directly, here we use the NUFFT linear map object defined in MIRT that provides a non-Cartesian Fourier encoding \"matrix\".","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"A = Anufft([vec(Ωx) vec(Ωy)], (N,N); n_shift = [N/2,N/2])","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"This linear map is constructed to map a N × N image into length(Ωx) k-space samples. So its adjoint goes the other direction. However, an adjoint is not an inverse!","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"gridded2 = A' * vec(data)\njim(x, y, gridded2, title=\"NUFFT gridding without DCF\")","category":"page"},{"location":"generated/mri/1-nufft/#Density-compensation","page":"NUFFT Overview","title":"Density compensation","text":"","category":"section"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"To get a decent image with NUFFT-based gridding of non-Cartesian data, one must compensate for the k-space sampling density. See this book chapter for details.","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"Because this example uses radial sampling, we can borrow ideas from tomography, especially the ramp filter, to define a reasonable density compensation function (DCF).","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"Here is a basic DCF version that uses the ramp filter in a simple way, corresponding to the areas of annular segments (Voronoi cells in polar coordinates). The dcf .* data line uses Julia's broadcast feature to apply the 1D DCF to each radial spoke.","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"dν = 1/FOV # k-space radial sample spacing\ndcf = pi / Nϕ * dν * abs.(kr) # (N+1) weights along k-space polar coordinate\ndcf = dcf / oneunit(eltype(dcf)) # kludge: units not working with LinearMap now\ngridded3 = A' * vec(dcf .* data)\np3 = jim(x, y, gridded3, title=\"NUFFT gridding with simple ramp-filter DCF\"; clim)","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"The image is more reasonable than without any DCF, but we can do better (quantitatively) using the correction of Lauzon&Rutt, 1996 and Joseph, 1998.","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"dcf = pi / Nϕ * dν * abs.(kr) # see lauzon:96:eop, joseph:98:sei\ndcf[kr .== 0/mm] .= pi * (dν/2)^2 / Nϕ # area of center disk\ndcf = dcf / oneunit(eltype(dcf)) # kludge: units not working with LinearMap now\ngridded4 = A' * vec(dcf .* data)\np4 = jim(x, y, gridded4, title=\"NUFFT gridding with better ramp-filter DCF\"; clim)","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"A profile helps illustrate the improvement.","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"pp = plot(x, real(gridded4[:,N÷2]), label=\"Modified ramp DCF\")\nplot!(x, real(gridded3[:,N÷2]), label=\"Basic ramp DCF\")\nplot!(x, real(ideal[:,N÷2]), label=\"Ideal\", xlabel=L\"x\", ylabel=\"middle profile\")","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"isinteractive() && prompt();\nnothing #hide","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"Finally we have made a NUFFT gridded image with DCF that has the appropriate range of values, but it still looks less than ideal. So next we try an iterative approach.","category":"page"},{"location":"generated/mri/1-nufft/#Iterative-MR-image-reconstruction-using-NUFFT","page":"NUFFT Overview","title":"Iterative MR image reconstruction using NUFFT","text":"","category":"section"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"As an initial iterative approach, let's apply a few iterations of conjugate gradient (CG) to seek the minimizer of the least-squares cost function:","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"arg min_x frac12  A x - y _2^2","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"CG is well-suited to minimizing quadratic cost functions, but we do not expect the image to be great quality because radial sampling omits the \"corners\" of k-space so the NUFFT operator A is badly conditioned.","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"dx = FOV / N # pixel size\ndx = dx / oneunit(dx) # abandon units for now\ngradf = u -> u - vec(data/dx^2) # gradient of f(u) = 1/2 \\| u - y \\|^2\ncurvf = u -> 1 # curvature of f(u)\nx0 = gridded4 # initial guess: best gridding reconstruction\nxls, _ = ncg([A], [gradf], [curvf], x0; niter = 20)\np5 = jim(x, y, xls, \"LS-CG reconstruction\"; clim)","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"To improve the results, we include regularization. Here we would like to reconstruct an image by finding the minimizer of a regularized LS cost function such as the following:","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"arg min_x frac12  A x - y _2^2 + beta R(x)\n qquad\nR(x) = 1 psi(T x)","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"We focus here on the case of edge-preserving regularization where T is a 2D finite-differencing operator and psi is a potential function. This operator maps a N×N image into a N×N×2 array with the horizontal and vertical finite differences.","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"T = diffl_map((N,N), [1,2] ; T = ComplexF32)","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"Applying this operator to the ideal image illustrated its action:","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"jim(x, y, T * ideal; ncol=1, title=\"Horizontal and vertical finite differences\")","category":"page"},{"location":"generated/mri/1-nufft/#Edge-preserving-regularization","page":"NUFFT Overview","title":"Edge-preserving regularization","text":"","category":"section"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"We use the Fair potential function: a rounded corner version of absolute value, an approximation to anisotropic total variation (TV).","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"β = 2^13 # regularization parameter\nδ = 0.05 # edge-preserving parameter\nwpot = z -> 1 / (1 + abs(z)/δ) # weighting function","category":"page"},{"location":"generated/mri/1-nufft/#Nonlinear-CG-algorithm","page":"NUFFT Overview","title":"Nonlinear CG algorithm","text":"","category":"section"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"We apply a (nonlinear) CG algorithm to seek the minimizer of the cost function. Nonlinear CG is well suited to convex problems that are locally quadratic like the regularized cost function considered here. See this survey paper for an overview of optimization methods for MRI.","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"B = [A, T] # see MIRT.ncg\ngradf = [u -> u - vec(data/dx^2), # data-term gradient, correct for pixel area\n         u -> β * (u .* wpot.(u))] # regularizer gradient\ncurvf = [u -> 1, u -> β] # curvature of quadratic majorizers\nx0 = gridded4 # initial guess is best gridding reconstruction\nxhat, _ = ncg(B, gradf, curvf, x0; niter = 90)\np6 = jim(x, y, xhat, \"Iterative reconstruction\"; clim)","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"Here is a comparison of the profiles.","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"plot!(pp, x, real(xls[:,N÷2]), label=\"LS-CG\")\nplot!(pp, x, real(xhat[:,N÷2]), label=\"Iterative edge-preserving\", color=:black)","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"isinteractive() && prompt();\nnothing #hide","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"In this case, iterative image reconstruction provides the best looking image. One might argue this simulation was doomed to succeed, because the phantom is piece-wise constant, which is the best case for edge-preserving regularization. On the other hand, this was not an inverse crime (see also here) because the k-space data came from the analytical spectrum of ellipses, rather than from a discrete image.","category":"page"},{"location":"generated/mri/1-nufft/#Caveats","page":"NUFFT Overview","title":"Caveats","text":"","category":"section"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"The phantom used here was real-valued, which is unrealistic (although the reconstruction methods did not \"know\" it was real).\nThis simulation is for a single-coil scan whereas modern MRI scanners generally use multiple receive coils.\nThere was no statistical noise in this simulation.","category":"page"},{"location":"generated/mri/1-nufft/#Reproducibility","page":"NUFFT Overview","title":"Reproducibility","text":"","category":"section"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"This page was generated with the following version of Julia:","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"using InteractiveUtils: versioninfo\nio = IOBuffer(); versioninfo(io); split(String(take!(io)), '\\n')","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"And with the following package versions","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"import Pkg; Pkg.status()","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"","category":"page"},{"location":"generated/mri/1-nufft/","page":"NUFFT Overview","title":"NUFFT Overview","text":"This page was generated using Literate.jl.","category":"page"},{"location":"#JuliaImageRecon-Examples","page":"Home","title":"JuliaImageRecon Examples","text":"","category":"section"},{"location":"#Overview","page":"Home","title":"Overview","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"https://github.com/JuliaImageRecon/Examples","category":"page"},{"location":"","page":"Home","title":"Home","text":"Image reconstruction examples in the Julia language, compiled using Literate and Documenter.","category":"page"},{"location":"#Getting-started-with-Julia","page":"Home","title":"Getting started with Julia","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"Install Julia from https://julialang.org\nLaunch the Julia app should open a Julia REPL.\nTo develop code, select an editor, preferably with Julia integration, such as VSCode or vim perhaps with tmux. Appropriate editor plug-ins are needed to use LaTeX-like tab-completion of unicode characters like ÷ ⊗ ⊕ ∘ × and α β γ.\nPeruse the reconstruction examples listed in the menu here. If your browser window is wide enough, you should see a menu to the left. If your window is narrow, you should see a hamburger menu button that will toggle open the examples menu sidebar.\nView the excellent documentation at JuliaImages\nCheck out some Julia tutorials, especially the one titled \"Just the Julia you need to get started in Data Science and ML\" by Raj Rao.","category":"page"},{"location":"#Getting-started-with-Julia-image-reconstruction","page":"Home","title":"Getting started with Julia image reconstruction","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"These examples show you Julia code and the corresponding output in an HTML format suitable for viewing in a web browser without installing any software.","category":"page"},{"location":"","page":"Home","title":"Home","text":"You could cut and paste portions of that Julia code into the Julia REPL, but that becomes tedious. Instead, click on the \"Edit on GitHub\" link (in the upper right, with github icon), where you can then download the entire Julia code file that generated any of these examples.","category":"page"},{"location":"","page":"Home","title":"Home","text":"For example, the code for the NUFFT example is at this url. After downloading such a file such as 1-nufft.jl, you can run it by typing include(\"1-nufft.jl\") at the Julia REPL.","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"EditURL = \"../../../lit/mri/4-cs-sense-2d.jl\"","category":"page"},{"location":"generated/mri/4-cs-sense-2d/#4-cs-sense-2d","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"","category":"section"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"This example illustrates how to perform 2D compressed sensing image reconstruction from Cartesian sampled MRI data for parallel MRI (sensitivity encoding) with 1-norm regularization of orthogonal wavelet coefficients, using the Julia language.","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"This page comes from a single Julia file: 4-cs-sense-2d.jl.","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"You can access the source code for such Julia documentation using the 'Edit on GitHub' link in the top right. You can view the corresponding notebook in nbviewer here: 4-cs-sense-2d.ipynb, or open it in binder here: 4-cs-sense-2d.ipynb.","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"This demo is somewhat similar to Fig. 3 in the survey paper \"Optimization methods for MR image reconstruction,\" in Jan 2020 IEEE Signal Processing Magazine, except","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"the sampling is 1D phase encoding instead of 2D,\nthere are multiple coils,\nwe use units (WIP - todo)\nthe simulation avoids inverse crimes.","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"Packages used in this demo (run Pkg.add as needed):","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"using ImagePhantoms: ellipse_parameters, SheppLoganBrainWeb, ellipse, phantom\nusing ImagePhantoms: mri_smap_fit, mri_spectra\n#using ImageFiltering: imfilter, centered\nusing ImageMorphology: dilate #, label_components # imfill\nusing LazyGrids: ndgrid\nusing ImageGeoms: embed, embed!\nusing MIRT: Aodwt, Asense\nusing MIRTjim: jim, prompt\nusing MIRT: ir_mri_sensemap_sim\nusing MIRT: pogm_restart\nusing LinearAlgebra: norm, dot\nusing LinearMapsAA: LinearMapAA\nusing Plots; default(markerstrokecolor=:auto, label=\"\")\nusing FFTW: fft!, bfft!, fftshift!\nusing Random: seed!\nusing InteractiveUtils: versioninfo","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"The following line is helpful when running this jl-file as a script; this way it will prompt user to hit a key after each image is displayed.","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"isinteractive() && jim(:prompt, true);\nnothing #hide","category":"page"},{"location":"generated/mri/4-cs-sense-2d/#Create-(synthetic)-data","page":"Compressed Sensing 2D pMRI ","title":"Create (synthetic) data","text":"","category":"section"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"Image geometry:","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"uu = 1\nfovs = (256, 256) .* uu\nnx, ny = (192, 256)\ndx, dy = fovs ./ (nx,ny)\nx = (-(nx÷2):(nx÷2-1)) * dx\ny = (-(ny÷2):(ny÷2-1)) * dy","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"Modified Shepp-Logan phantom with random complex phases per ellipse","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"object = ellipse_parameters(SheppLoganBrainWeb() ; disjoint=true, fovs)\nseed!(0)\nobject = vcat( (object[1][1:end-1]..., 1), # random phases\n    [(ob[1:end-1]..., randn(ComplexF32)) for ob in object[2:end]]...)\nobject = ellipse(object)\noversample = 3\nXtrue = phantom(x, y, object, oversample)\ncfun = z -> cat(dims = ndims(z)+1, real(z), imag(z))\njim(:aspect_ratio, :equal)\njim(x, y, cfun(Xtrue), \"True image\\n real | imag\"; ncol=2)","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"Mask (support for image reconstruction)","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"mask = abs.(Xtrue) .> 0\nmask = dilate(dilate(dilate(mask))) # repeated dilate with 3×3 square\n@assert mask .* Xtrue == Xtrue\njim(x, y, mask + abs.(Xtrue), \"Mask + |Xtrue|\")","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"Make sensitivity maps, normalized so SSoS = 1:","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"ncoil = 4\nsmap_raw = ir_mri_sensemap_sim(dims=(nx,ny); ncoil, orbit_start=[45])\njif(args...; kwargs...) = jim(args...; prompt=false, kwargs...)\np1 = jif(x, y, smap_raw, \"Sensitivity maps raw\");\n\nsum_last = (f, x) -> selectdim(sum(f, x; dims=ndims(x)), ndims(x), 1)\nssos_fun = smap -> sqrt.(sum_last(abs2, smap)) # SSoS\nssos_raw = ssos_fun(smap_raw) # SSoS raw\np2 = jif(x, y, ssos_raw, \"SSoS raw, ncoil=$ncoil\");\n\nsmap = @. smap_raw / ssos_raw * mask # normalize and mask\nssos = ssos_fun(smap) # SSoS\n@assert all(≈(1), @view ssos[mask]) # verify ≈ 1\nsmaps = [eachslice(smap; dims = ndims(smap))...] # stack\np3 = jif(x, y, smaps, \"|Sensitivity maps normalized|\")\np4 = jif(x, y, map(x -> angle.(x), smaps), \"∠Sensitivity maps\"; color=:hsv)\njim(p1, p2, p3, p4)","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"Frequency sample vectors; crucial to match mri_smap_basis internals!","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"fx = (-(nx÷2):(nx÷2-1)) / (nx*dx)\nfy = (-(ny÷2):(ny÷2-1)) / (ny*dy)\ngx, gy = ndgrid(fx, fy);\nnothing #hide","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"Somewhat random 1D phase-encode sampling:","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"seed!(0); sampfrac = 0.3; samp = rand(ny÷2) .< sampfrac\ntmp = rand(ny÷2) .< 0.5; samp = [samp .* tmp; reverse(samp .* .!tmp)] # symmetry\nsamp .|= (abs.(fy*dy) .< 1/8) # fully sampled center ±1/8 phase-encodes\nny_count = count(samp)\nsamp = trues(nx) * samp'\nsamp_frac = round(100*count(samp) / (nx*ny), digits=2)\njim(fx, fy, samp, title=\"k-space sampling ($ny_count / $ny = $samp_frac%)\")","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"To avoid an inverse crime, here we use the 2012 method of Guerquin-Kern et al. and use the analytical k-space values of the phantom combined with an analytical model for the sensitivity maps.","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"kmax = 7\nfit = mri_smap_fit(smaps, embed; mask, kmax, deltas=(dx,dy))\njim(\n jif(x, y, cfun(smaps), \"Original maps\"; clim=(-1,1), nrow=4),\n jif(x, y, cfun(fit.smaps), \"Fit maps\"; clim=(-1,1), nrow=4),\n jif(x, y, cfun(100 * (fit.smaps - smaps)), \"error * 100\"; nrow=4),\n layout = (1,3),\n)","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"Analytical spectra computation for complex phantom using all smaps. (No inverse crime here.)","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"ytrue = mri_spectra(gx[samp], gy[samp], object, fit)\nytrue = hcat(ytrue...)\nytrue = ComplexF32.(ytrue) # save memory\nsize(ytrue)","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"Noisy under-sampled k-space data:","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"sig = 1\nydata = ytrue + oneunit(eltype(ytrue)) *\n    sig * √(2f0) * randn(ComplexF32, size(ytrue)) # complex noise with units!\nysnr = 20 * log10(norm(ytrue) / norm(ydata - ytrue)) # data SNR in dB","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"Display zero-filled data:","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"logger = (x; min=-6, up=maximum(abs,x)) -> log10.(max.(abs.(x) / up, (10.)^min))\njim(:abswarn, false) # suppress warnings about showing magnitude\ntmp = embed(ytrue[:,1],samp)\njim(\n jif(fx, fy, logger(tmp),\n    title=\"k-space |data|\\n(zero-filled, coil 1)\",\n    xlabel=\"νx\", ylabel=\"νy\"),\n jif(fx, fy, angle.(tmp),\n    title=\"∠data, coil 1\"; color=:hsv)\n)","category":"page"},{"location":"generated/mri/4-cs-sense-2d/#Prepare-to-reconstruct","page":"Compressed Sensing 2D pMRI ","title":"Prepare to reconstruct","text":"","category":"section"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"Create a system matrix (encoding matrix) and an initial image.","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"The system matrix is a LinearMapAO object, akin to a fatrix in Matlab MIRT.","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"This system model (\"encoding matrix\") is for a 2D image x being mapped to an array of size count(samp) × ncoil k-space data.","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"Here we construct it from FFT and coil map components. So this is like \"seeing the sausage being made.\"","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"The dx * dy scale factor here is required because the true k-space data ytrue comes from an analytical Fourier transform, but the reconstruction uses a discrete Fourier transform. This factor is also needed from a unit-balance perspective.","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"Ascale = Float32(dx * dy)\nA = Ascale * Asense(samp, smaps) # operator!\n(size(A), A._odim, A._idim)","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"Compare the analytical k-space data with the discrete model k-space data:","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"y0 = embed(ytrue, samp) # analytical\ny1 = embed(A * Xtrue, samp) # discrete\njim(\n jif(logger(y0; up=maximum(abs,y0)), \"analytical\"; clim=(-6,0)),\n jif(logger(y1; up=maximum(abs,y0)), \"discrete\"; clim=(-6,0)),\n jif(logger(y1 - y0; up=maximum(abs,y0)), \"difference\"),\n)\nnorm(y1) / norm(y0) # scale factor is ≈1","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"Initial image based on zero-filled adjoint reconstruction. Note the (dx*dy)² scale factor here!","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"nrmse = (x) -> round(norm(x - Xtrue) / norm(Xtrue) * 100, digits=1)\nX0 = 1.0f0/(nx*ny) * (A' * ydata) / (dx*dy)^2\njim(x, y, X0, \"|X0|: initial image; NRMSE $(nrmse(X0))%\")","category":"page"},{"location":"generated/mri/4-cs-sense-2d/#Wavelet-sparsity-in-synthesis-form","page":"Compressed Sensing 2D pMRI ","title":"Wavelet sparsity in synthesis form","text":"","category":"section"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"The image reconstruction optimization problem here is","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"arg min_x\nfrac12  A x - y _2^2 + beta   W x _1","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"where","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"y is the k-space data,\nA is the system model (simply Fourier encoding F here),\nW is an orthogonal discrete (Haar) wavelet transform, again implemented as a LinearMapAA object.","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"Because W is unitary, we make the change of variables z = W x and solve for z and then let x = W z at the end. In fact we use a weighted 1-norm where only the detail wavelet coefficients are regularized, not the approximation coefficients.","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"Orthogonal discrete wavelet transform operator (LinearMapAO):","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"W, scales, _ = Aodwt((nx,ny) ; T = eltype(A))\nisdetail = scales .> 0\njim(\n jif(scales, \"wavelet scales\"),\n jif(real(W * Xtrue) .* isdetail, \"wavelet detail coefficients\\nreal for Xtrue\"),\n)","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"Inputs needed for proximal gradient methods. The trickiest part of this is determining a bound on the Lipschitz constant, i.e., the spectral norm of (AW)(AW), which is the same as the spectral norm of AA because W is unitary. Here we have SSOS=1 for the coil maps, so we just need to account for the number of voxels (because fft & bfft are not the unitary DFT) and for the scale factor. (If SSOS was nonuniform, we would use eqn. (6) of Matt Muckley's BARISTA paper. Submit an issue if you need an example using that.)","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"f_Lz = Ascale^2 * nx*ny # Lipschitz constant\nAz = A * W' # another operator!\nFnullz = (z) -> 0 # cost function in `z` not needed\nf_gradz = (z) -> Az' * (Az * z - ydata)\nregz = 0.03 * nx * ny # oracle from Xtrue wavelet coefficients!\ncostz = (z) -> 1/2 * norm(Az * z - ydata)^2 + regz * norm(z,1) # 1-norm regularizer\nsoft = (z,c) -> sign(z) * max(abs(z) - c, 0) # soft thresholding\ng_prox = (z,c) -> soft.(z, isdetail .* (regz * c)) # proximal operator (shrink details only)\nz0 = W * X0\njim(\n jif(z0, \"|wavelet coefficients|\"),\n jif(z0 .* isdetail, \"|detail coefficients|\"),\n ; plot_title = \"Initial\",\n)","category":"page"},{"location":"generated/mri/4-cs-sense-2d/#Iterate","page":"Compressed Sensing 2D pMRI ","title":"Iterate","text":"","category":"section"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"Run ISTA=PGM and FISTA=FPGM and POGM, the latter two with adaptive restart. See Kim & Fessler, 2018 for adaptive restart algorithm details.","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"Functions for tracking progress:","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"function fun_ista(iter, xk_z, yk, is_restart)\n    xh = W' * xk_z\n    return (costz(xk_z), nrmse(xh), is_restart) # , psnr(xh) # time()\nend\n\nfunction fun_fista(iter, xk, yk_z, is_restart)\n    xh = W' * yk_z\n    return (costz(yk_z), nrmse(xh), is_restart) # , psnr(xh) # time()\nend;\nnothing #hide","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"Run and compare three proximal gradient methods:","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"niter = 20\nz_ista, out_ista = pogm_restart(z0, Fnullz, f_gradz, f_Lz;\n    mom=:pgm, niter,\n    restart=:none, restart_cutoff=0., g_prox, fun=fun_ista)\nXista = W'*z_ista\n@show nrmse(Xista)\n\nz_fista, out_fista = pogm_restart(z0, Fnullz, f_gradz, f_Lz;\n    mom=:fpgm, niter,\n    restart=:gr, restart_cutoff=0., g_prox, fun=fun_fista)\nXfista = W'*z_fista\n@show nrmse(Xfista)\n\nz_pogm, out_pogm = pogm_restart(z0, Fnullz, f_gradz, f_Lz;\n    mom=:pogm, niter,\n    restart=:gr, restart_cutoff=0., g_prox, fun=fun_fista)\nXpogm = W'*z_pogm\n@show nrmse(Xpogm)\n\njim(\n jif(x, y, Xfista, \"FISTA/FPGM\"),\n jif(x, y, Xpogm, \"POGM with ODWT\"),\n)","category":"page"},{"location":"generated/mri/4-cs-sense-2d/#Convergence-rate:-POGM-is-fastest","page":"Compressed Sensing 2D pMRI ","title":"Convergence rate: POGM is fastest","text":"","category":"section"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"Plot cost function vs iteration:","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"cost_ista = [out_ista[k][1] for k in 1:niter+1]\ncost_fista = [out_fista[k][1] for k in 1:niter+1]\ncost_pogm = [out_pogm[k][1] for k in 1:niter+1]\ncost_min = min(minimum(cost_ista), minimum(cost_pogm))\npc = plot(xlabel=\"iteration k\", ylabel=\"Relative cost\")\nscatter!(0:niter, cost_ista  .- cost_min, label=\"Cost ISTA\")\nscatter!(0:niter, cost_fista .- cost_min, markershape=:square, label=\"Cost FISTA\")\nscatter!(0:niter, cost_pogm  .- cost_min, markershape=:utriangle, label=\"Cost POGM\")","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"isinteractive() && prompt();\nnothing #hide","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"Plot NRMSE vs iteration:","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"nrmse_ista = [out_ista[k][2] for k in 1:niter+1]\nnrmse_fista = [out_fista[k][2] for k in 1:niter+1]\nnrmse_pogm = [out_pogm[k][2] for k in 1:niter+1]\npn = plot(xlabel=\"iteration k\", ylabel=\"NRMSE %\")#, ylims=(3,6.5))\nscatter!(0:niter, nrmse_ista, label=\"NRMSE ISTA\")\nscatter!(0:niter, nrmse_fista, markershape=:square, label=\"NRMSE FISTA\")\nscatter!(0:niter, nrmse_pogm, markershape=:utriangle, label=\"NRMSE POGM\")","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"isinteractive() && prompt();\nnothing #hide","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"Show error images:","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"snrfun = (x) -> round(-20log10(nrmse(x)/100); digits=1)\np1 = jif(x, y, Xtrue, \"|true|\"; clim=(0,2.5))\np2 = jif(x, y, X0, \"|X0|: initial\"; clim=(0,2.5))\np3 = jif(x, y, Xpogm, \"|POGM recon|\"; clim=(0,2.5))\np5 = jif(x, y, X0 - Xtrue, \"|X0 error|\"; clim=(0,1), color=:cividis,\n   xlabel = \"NRMSE = $(nrmse(X0))%\\n SNR = $(snrfun(X0)) dB\")\np6 = jif(x, y, Xpogm - Xtrue, \"|Xpogm error|\"; clim=(0,1), color=:cividis,\n   xlabel = \"NRMSE = $(nrmse(Xpogm))%\\n SNR = $(snrfun(Xpogm)) dB\")\npe = jim(p2, p3, p5, p6)","category":"page"},{"location":"generated/mri/4-cs-sense-2d/#Discussion","page":"Compressed Sensing 2D pMRI ","title":"Discussion","text":"","category":"section"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"As reported in the optimization survey paper cited above, POGM converges faster than ISTA and FISTA.","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"The final images serve as a reminder that NRMSE (and PSNR) and dubious image quality metrics. The NRMSE after 20 iterations may seem only a bit lower than the NRMSE of the initial image, but aliasing artifacts (ripples) were greatly reduced by the CS-SENSE reconstruction method.","category":"page"},{"location":"generated/mri/4-cs-sense-2d/#Reproducibility","page":"Compressed Sensing 2D pMRI ","title":"Reproducibility","text":"","category":"section"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"This page was generated with the following version of Julia:","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"using InteractiveUtils: versioninfo\nio = IOBuffer(); versioninfo(io); split(String(take!(io)), '\\n')","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"And with the following package versions","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"import Pkg; Pkg.status()","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"","category":"page"},{"location":"generated/mri/4-cs-sense-2d/","page":"Compressed Sensing 2D pMRI ","title":"Compressed Sensing 2D pMRI ","text":"This page was generated using Literate.jl.","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"EditURL = \"../../../lit/mri/5-l-plus-s.jl\"","category":"page"},{"location":"generated/mri/5-l-plus-s/#5-l-plus-s","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"","category":"section"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"This page illustrates dynamic parallel MRI image reconstruction using a low-rank plus sparse (L+S) model optimized by a fast algorithm described in the paper by Claire Lin and Jeff Fessler Efficient Dynamic Parallel MRI Reconstruction for the Low-Rank Plus Sparse Model, IEEE Trans. on Computational Imaging, 5(1):17-26, 2019, by Claire Lin and Jeff Fessler, EECS Department, University of Michigan.","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"The Julia code here is a translation of part of the Matlab code used in the original paper.","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"If you use this code, please cite that paper.","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"This page comes from a single Julia file: 5-l-plus-s.jl.","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"You can access the source code for such Julia documentation using the 'Edit on GitHub' link in the top right. You can view the corresponding notebook in nbviewer here: 5-l-plus-s.ipynb, or open it in binder here: 5-l-plus-s.ipynb.","category":"page"},{"location":"generated/mri/5-l-plus-s/#Setup","page":"L+S 2D dynamic recon","title":"Setup","text":"","category":"section"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Packages needed here.","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"# using Unitful: s\nusing Plots; cgrad, default(markerstrokecolor=:auto, label=\"\")\nusing MIRT: Afft, Asense, embed\nusing MIRT: pogm_restart, poweriter\nusing MIRTjim: jim, prompt\nusing FFTW: fft!, bfft!, fftshift!\nusing LinearMapsAA: LinearMapAA, block_diag, redim, undim\nusing MAT: matread\nimport Downloads # todo: use Fetch or DataDeps?\nusing LinearAlgebra: dot, norm, svd, svdvals, Diagonal, I\nusing Random: seed!\nusing StatsBase: mean\nusing LaTeXStrings","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"The following line is helpful when running this file as a script; this way it will prompt user to hit a key after each figure is displayed.","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"jif(args...; kwargs...) = jim(args...; prompt=false, kwargs...)\nisinteractive() ? jim(:prompt, true) : prompt(:draw);\nnothing #hide","category":"page"},{"location":"generated/mri/5-l-plus-s/#Overview","page":"L+S 2D dynamic recon","title":"Overview","text":"","category":"section"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Dynamic image reconstruction using a \"low-rank plus sparse\" or \"L+S\" approach was proposed by Otazo et al. and uses the following cost function:","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"X = hatL + hatS\nqquad\n(hatL hatS)\n= arg min_LS frac12  E (L + S) - d _2^2\n + λ_L  L _*\n + λ_S  vec(T S) _1","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"where T is a temporal unitary FFT, E is an encoding operator (system matrix), and d is Cartesian undersampled multicoil k-space data.","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"The Otazo paper used an iterative soft thresholding algorithm (ISTA) to solve this optimization problem. Using FISTA is faster, but using the proximal optimized gradient method (POGM) with adaptive restart is even faster.","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"This example reproduces part of Figures 1 & 2 in Claire Lin's paper, based on the cardiac perfusion example.","category":"page"},{"location":"generated/mri/5-l-plus-s/#Read-data","page":"L+S 2D dynamic recon","title":"Read data","text":"","category":"section"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"if !@isdefined(data)\n    url = \"https://github.com/JeffFessler/MIRTdata/raw/main/mri/lin-19-edp/\"\n    dataurl = url * \"cardiac_perf_R8.mat\"\n    data = matread(Downloads.download(dataurl))\n    xinfurl = url * \"Xinf.mat\"\n    Xinf = matread(Downloads.download(xinfurl))[\"Xinf\"][\"perf\"] # (128,128,40)\nend;\nnothing #hide","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Show converged image as a preview:","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"pinf = jim(Xinf, L\"\\mathrm{Converged\\ image\\ sequence } X_∞\")","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Organize k-space data:","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"if !@isdefined(ydata0)\n    ydata0 = data[\"kdata\"] # k-space data full of zeros\n    ydata0 = permutedims(ydata0, [1, 2, 4, 3]) # (nx,ny,nc,nt)\n    ydata0 = ComplexF32.(ydata0)\nend\n(nx, ny, nc, nt) = size(ydata0)","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Extract sampling pattern from zeros of k-space data:","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"if !@isdefined(samp)\n    samp = ydata0[:,:,1,:] .!= 0\n    for ic in 2:nc # verify it is same for all coils\n        @assert samp == (ydata0[:,:,ic,:] .!= 0)\n    end\n    kx = -(nx÷2):(nx÷2-1)\n    ky = -(ny÷2):(ny÷2-1)\n    psamp = jim(kx, ky, samp, \"Sampling patterns for $nt frames\";\n       xlabel=L\"k_x\", ylabel=L\"k_y\")\nend","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Are all k-space rows are sampled in one of the 40 frames? Sadly no. The 10 blue rows shown below are never sampled. A better sampling pattern design could have avoided this issue.","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"samp_sum = sum(samp, dims=3)\ncolor = cgrad([:blue, :black, :white], [0, 1/2nt, 1])\npssum = jim(kx, ky, samp_sum; xlabel=\"kx\", ylabel=\"ky\",\n    color, clim=(0,nt), title=\"Number of sampled frames out of $nt\")","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Prepare coil sensitivity maps","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"if !@isdefined(smaps)\n    smaps_raw = data[\"b1\"] # raw coil sensitivity maps\n    jim(smaps_raw, \"Raw |coil maps| for $nc coils\")\n    sum_last = (f, x) -> selectdim(sum(f, x; dims=ndims(x)), ndims(x), 1)\n    ssos_fun = smap -> sqrt.(sum_last(abs2, smap)) # SSoS\n    ssos_raw = ssos_fun(smaps_raw)\n    smaps = smaps_raw ./ ssos_raw\n    ssos = ssos_fun(smaps)\n    @assert all(≈(1), ssos)\n    pmap = jim(smaps, \"Normalized |coil maps| for $nc coils\")\nend","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Temporal unitary FFT sparsifying transform for image sequence of size (nx, ny, nt):","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"TF = Afft((nx,ny,nt), 3; unitary=true) # unitary FFT along 3rd (time) dimension\nif false # verify adjoint\n    tmp1 = randn(ComplexF32, nx, ny, nt)\n    tmp2 = randn(ComplexF32, nx, ny, nt)\n    @assert dot(tmp2, TF * tmp1) ≈ dot(TF' * tmp2, tmp1)\n    @assert TF' * (TF * tmp1) ≈ tmp1\n    (size(TF), TF._odim, TF._idim)\nend","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Examine temporal Fourier sparsity of Xinf. The low temporal frequencies dominate, as expected, because Xinf was reconstructed using this regularizer!","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"tmp = TF * Xinf\nptfft = jim(tmp, \"|Temporal FFT of Xinf|\")","category":"page"},{"location":"generated/mri/5-l-plus-s/#System-matrix","page":"L+S 2D dynamic recon","title":"System matrix","text":"","category":"section"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Construct dynamic parallel MRI system model. It is block diagonal where each frame has its own sampling pattern. The input (image) here has size (nx=128, ny=128, nt=40). The output (data) has size (nsamp=2048, nc=12, nt=40) because every frame has 16 phase-encode lines of 128 samples.","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"todo: precompute (i)fft along readout direction to save time","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"The code in the original Otazo et al. paper used an ifft in the forward model and an fft in the adjoint, so we must use a flag here to match that model.","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Aotazo = (samp, smaps) -> Asense(samp, smaps; unitary=true, fft_forward=false) # Otazo style\nA = block_diag([Aotazo(s, smaps) for s in eachslice(samp, dims=3)]...)\n#A = ComplexF32(1/sqrt(nx*ny)) * A # match Otazo's scaling\n(size(A), A._odim, A._idim)","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Reshape data to match the system model","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"if !@isdefined(ydata)\n    tmp = reshape(ydata0, :, nc, nt)\n    tmp = [tmp[vec(s),:,it] for (it,s) in enumerate(eachslice(samp, dims=3))]\n    ydata = cat(tmp..., dims=3) # (nsamp,nc,nt) = (2048,12,40) no \"zeros\"\nend\nsize(ydata)","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Final encoding operator E for L+S because we stack X = [L;S]","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"tmp = LinearMapAA(I(nx*ny*nt);\n    odim=(nx,ny,nt), idim=(nx,ny,nt), T=ComplexF32, prop=(;name=\"I\"))\ntmp = kron([1 1], tmp)\nAII = redim(tmp; odim=(nx,ny,nt), idim=(nx,ny,nt,2)) # \"squeeze\" odim\nE = A * AII;\nnothing #hide","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Run power iteration to verify that opnorm(E) = √2","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"if false\n    (_, σ1E) = poweriter(undim(E)) # 1.413 ≈ √2\nelse\n    σ1E = √2\nend","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Check scale factor of Xinf. (It should be ≈1.)","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"tmp = A * Xinf\nscale0 = dot(tmp, ydata) / norm(tmp)^2 # 1.009 ≈ 1","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Crude initial image","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"L0 = A' * ydata # adjoint (zero-filled)\nS0 = zeros(ComplexF32, nx, ny, nt)\nX0 = cat(L0, S0, dims=ndims(L0)+1) # (nx, ny, nt, 2) = (128, 128, 40, 2)\nM0 = AII * X0 # L0 + S0\npm0 = jim(M0, \"|Initial L+S via zero-filled recon|\")","category":"page"},{"location":"generated/mri/5-l-plus-s/#LS-reconstruction","page":"L+S 2D dynamic recon","title":"L+S reconstruction","text":"","category":"section"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Prepare for proximal gradient methods","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Scalars to match Otazo's results","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"scaleL = 130 / 1.2775 # Otazo's stopping St(1) / b1 constant squared\nscaleS = 1 / 1.2775; # 1 / b1 constant squared\nnothing #hide","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"L+S regularizer","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"lambda_L = 0.01 # regularization parameter\nlambda_S = 0.01 * scaleS\nLpart = X -> selectdim(X, ndims(X), 1) # extract \"L\" from X\nSpart = X -> selectdim(X, ndims(X), 2) # extract \"S\" from X\nnucnorm(L::AbstractMatrix) = sum(svdvals(L)) # nuclear norm\nnucnorm(L::AbstractArray) = nucnorm(reshape(L, :, nt)); # (nx*ny, nt) for L\nnothing #hide","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Optimization overall composite cost function","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Fcost = X -> 0.5 * norm(E * X - ydata)^2 +\n    lambda_L * scaleL * nucnorm(Lpart(X)) + # note scaleL !\n    lambda_S * norm(TF * Spart(X), 1);\n\nf_grad = X -> E' * (E * X - ydata); # gradient of data-fit term","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Lipschitz constant of data-fit term is 2 because A is unitary and AII is like ones(2,2).","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"f_L = 2; # σ1E^2\nnothing #hide","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Proximal operator for scaled nuclear norm β  X _*: singular value soft thresholding (SVST).","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"function SVST(X::AbstractArray, β)\n    dims = size(X)\n    X = reshape(X, :, dims[end]) # assume time frame is the last dimension\n    U,s,V = svd(X)\n    sthresh = @. max(s - β, 0)\n    keep = findall(>(0), sthresh)\n    X = U[:,keep] * Diagonal(sthresh[keep]) * V[:,keep]'\n    X = reshape(X, dims)\n    return X\nend;\nnothing #hide","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Combine proximal operators for L and S parts to make overall prox for X","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"soft = (v,c) -> sign(v) * max(abs(v) - c, 0) # soft threshold function\nS_prox = (S, β) -> TF' * soft.(TF * S, β) # 1-norm proximal mapping for unitary TF\ng_prox = (X, c) -> cat(dims=ndims(X),\n    SVST(Lpart(X), c * lambda_L * scaleL),\n    S_prox(Spart(X), c * lambda_S),\n);\n\nif false # check functions\n    @assert Fcost(X0) isa Real\n    tmp = f_grad(X0)\n    @assert size(tmp) == size(X0)\n    tmp = SVST(Lpart(X0), 1)\n    @assert size(tmp) == size(L0)\n    tmp = S_prox(S0, 1)\n    @assert size(tmp) == size(S0)\n    tmp = g_prox(X0, 1)\n    @assert size(tmp) == size(X0)\nend\n\n\nniter = 10\nfun = (iter, xk, yk, is_restart) -> (Fcost(xk), xk); # logger\nnothing #hide","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Run PGM","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"if !@isdefined(Mpgm)\n    f_mu = 2/0.99 - f_L # trick to match 0.99 step size in Lin 1999\n    f_mu = 0\n    xpgm, out_pgm = pogm_restart(X0, (x) -> 0, f_grad, f_L ;\n        f_mu, mom = :pgm, niter, g_prox, fun)\n    Mpgm = AII * xpgm\nend;\nnothing #hide","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Run FPGM (FISTA)","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"if !@isdefined(Mfpgm)\n    xfpgm, out_fpgm = pogm_restart(X0, (x) -> 0, f_grad, f_L ;\n        mom = :fpgm, niter, g_prox, fun)\n    Mfpgm = AII * xfpgm\nend;\nnothing #hide","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Run POGM","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"if !@isdefined(Mpogm)\n    xpogm, out_pogm = pogm_restart(X0, (x) -> 0, f_grad, f_L ;\n        mom = :pogm, niter, g_prox, fun)\n    Mpogm = AII * xpogm\nend;\nnothing #hide","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Look at final POGM image components","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"px = jim(\n jif(Lpart(xpogm), \"L\"),\n jif(Spart(xpogm), \"S\"),\n jif(Mpogm, \"M=L+S\"),\n jif(Xinf, \"Minf\"),\n)","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Plot cost function","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"costs = out -> [o[1] for o in out]\nnrmsd = out -> [norm(AII*o[2]-Xinf)/norm(Xinf) for o in out]\ncost_pgm = costs(out_pgm)\ncost_fpgm = costs(out_fpgm)\ncost_pogm = costs(out_pogm)\npc = plot(xlabel = \"iteration\", ylabel = \"cost\")\nplot!(0:niter, cost_pgm, marker=:circle, label=\"PGM (ISTA)\")\nplot!(0:niter, cost_fpgm, marker=:square, label=\"FPGM (FISTA)\")\nplot!(0:niter, cost_pogm, marker=:star, label=\"POGM\")","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"Plot NRMSD vs Matlab Xinf","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"nrmsd_pgm = nrmsd(out_pgm)\nnrmsd_fpgm = nrmsd(out_fpgm)\nnrmsd_pogm = nrmsd(out_pogm)\npd = plot(xlabel = \"iteration\", ylabel = \"NRMSD vs Matlab Xinf\")\nplot!(0:niter, nrmsd_pgm, marker=:circle, label=\"PGM (ISTA)\")\nplot!(0:niter, nrmsd_fpgm, marker=:square, label=\"FPGM (FISTA)\")\nplot!(0:niter, nrmsd_pogm, marker=:star, label=\"POGM\")","category":"page"},{"location":"generated/mri/5-l-plus-s/#Discussion","page":"L+S 2D dynamic recon","title":"Discussion","text":"","category":"section"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"todo","category":"page"},{"location":"generated/mri/5-l-plus-s/#Reproducibility","page":"L+S 2D dynamic recon","title":"Reproducibility","text":"","category":"section"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"This page was generated with the following version of Julia:","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"using InteractiveUtils: versioninfo\nio = IOBuffer(); versioninfo(io); split(String(take!(io)), '\\n')","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"And with the following package versions","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"import Pkg; Pkg.status()","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"","category":"page"},{"location":"generated/mri/5-l-plus-s/","page":"L+S 2D dynamic recon","title":"L+S 2D dynamic recon","text":"This page was generated using Literate.jl.","category":"page"}]
